mapper.select:
SELECT DISTINCT s.* FROM ccpc.signup s LEFT JOIN ccpc.competition c ON s.competition_id = c.id LEFT JOIN ccpc.signup_member sm ON s.id = sm.signup_id LEFT JOIN ccpc.user u1 ON sm.member_id = u1.id LEFT JOIN ccpc.user u2 ON s.coach_id = u2.id WHERE #{coachId} = s.coach_id
AND c.name LIKE CONCAT('%', #{competition}, '%')
AND s.team_name LIKE CONCAT('%', #{teamName}, '%')
AND s.process_status = #{processStatus}
AND s.occupation_quota_type = #{occupationQuotaType}
AND ( CONCAT(u2.first_name, u2.last_name) LIKE CONCAT('%', #{coachName}, '%') OR CONCAT(u2.last_name, u2.first_name) LIKE CONCAT('%', #{coachName}, '%') )
AND (
CONCAT(u1.first_name, u1.last_name) LIKE CONCAT('%', #{name}, '%') OR CONCAT(u1.last_name, u1.first_name) LIKE CONCAT('%', #{name}, '%')
)
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(DISTINCT s.id) FROM ccpc.signup s LEFT JOIN ccpc.competition c ON s.competition_id = c.id LEFT JOIN ccpc.signup_member sm ON s.id = sm.signup_id LEFT JOIN ccpc.user u1 ON sm.member_id = u1.id LEFT JOIN ccpc.user u2 ON s.coach_id = u2.id WHERE #{coachId} = s.coach_id
AND c.name LIKE CONCAT('%', #{competition}, '%')
AND s.team_name LIKE CONCAT('%', #{teamName}, '%')
AND s.process_status = #{processStatus}
AND s.occupation_quota_type = #{occupationQuotaType}
AND ( CONCAT(u2.first_name, u2.last_name) LIKE CONCAT('%', #{coachName}, '%') OR CONCAT(u2.last_name, u2.first_name) LIKE CONCAT('%', #{coachName}, '%') )
AND (
CONCAT(u1.first_name, u1.last_name) LIKE CONCAT('%', #{name}, '%') OR CONCAT(u1.last_name, u1.first_name) LIKE CONCAT('%', #{name}, '%')
)
